for (const item of $input.all()) {
  const fileContent = item.json.data || ""; 

  // This regex finds everything between the two --- marks at the top
  const frontmatterRegex = /^---\s*\n([\s\S]*?)\n---\s*\n?([\s\S]*)$/;
  const match = fileContent.match(frontmatterRegex);

  if (match) {
    const yamlString = match[1];
    const bodyContent = match[2];

    const metadata = {};
    let currentKey = null; 

    // Variables to track multiline strings (like |-)
    let isMultiline = false;
    let multilineIndent = '';

    // Split YAML by lines
    yamlString.split('\n').forEach(line => {
      const isEmpty = line.trim() === '';
      const isIndented = /^\s+/.test(line);

      // 1. If we are currently parsing a multiline string...
      if (isMultiline) {
        // A multiline string ends when we encounter a non-empty, non-indented line
        if (!isEmpty && !isIndented) {
          isMultiline = false; // End of multiline block
        } else {
          // Strip the base indentation (usually 2 spaces) to preserve formatting
          let cleanedLine = line;
          if (multilineIndent && line.startsWith(multilineIndent)) {
            cleanedLine = line.substring(multilineIndent.length);
          } else if (isIndented && !multilineIndent) {
            // Determine the base indent from the first indented line
            const indentMatch = line.match(/^(\s+)/);
            if (indentMatch) multilineIndent = indentMatch[1];
            cleanedLine = line.substring(multilineIndent.length);
          }

          if (metadata[currentKey] === "") {
            metadata[currentKey] = cleanedLine;
          } else {
            metadata[currentKey] += '\n' + cleanedLine;
          }
          return; // Move to next line so we don't process it as a key
        }
      }

      // 2. Check if the line is a multi-line list item (e.g., "  - Twitter")
      const listMatch = line.match(/^\s*-\s+(.*)$/);

      if (listMatch && currentKey) {
        let listItemValue = listMatch[1].trim();
        // Remove quotes if present on the list item
        listItemValue = listItemValue.replace(/^["'](.+)["']$/, '$1');

        // If the current key isn't an array yet, convert it to one
        if (!Array.isArray(metadata[currentKey])) {
          metadata[currentKey] = [];
        }
        metadata[currentKey].push(listItemValue);
        return; // Move to the next line so we don't process it as a key
      }

      // 3. Otherwise, treat it as a standard "key: value" line
      // Use regex to strictly enforce that the key is at the start of the line
      const keyMatch = line.match(/^([a-zA-Z0-9_ -]+):\s*(.*)$/);

      if (keyMatch) {
        currentKey = keyMatch[1].trim().toLowerCase();
        let value = keyMatch[2].trim();

        // Check if the value is a multiline indicator
        if (value === '|-' || value === '|' || value === '>-' || value === '>') {
          isMultiline = true;
          multilineIndent = ''; // reset indent tracker
          metadata[currentKey] = ""; // initiate empty string
        } else {
          // Basic cleanup: Remove quotes if present
          value = value.replace(/^["'](.+)["']$/, '$1');

          // Basic cleanup: Turn inline [a, b] into an actual list
          if (value.startsWith('[') && value.endsWith(']')) {
            value = value.slice(1, -1).split(',').map(v => {
               // also clean quotes out of inline array items
               return v.trim().replace(/^["'](.+)["']$/, '$1'); 
            });
          }

          metadata[currentKey] = value;
        }
      }
    });

    // Add the parsed data and the note body back to the item
    item.json.metadata = metadata;
    item.json.note_body = bodyContent.trim();
  } else {
    // If no YAML is found, just keep the content as is
    item.json.note_body = fileContent.trim();
    item.json.metadata = {};
  }
}

return $input.all();

