// Get the first item coming into this node
const item = $input.first();

// Get the post text using the exact path you found
const postText = item.json.property_final_post;

// --- This is the most important part ---
// We must check if the text actually exists before we try to process it.
// This prevents errors if the input data is ever empty.
if (typeof postText === 'string') {

  // JSON.stringify() is the Code node equivalent of the .json() method.
  // It wraps the string in quotes and escapes any internal quotes.
  // Example: "Hello" becomes "\"Hello\""
  let escapedText = JSON.stringify(postText);

  // For a social media post, we don't want the outer quotes.
  // This line removes the first character (") and the last character (").
  item.json.safe_text = escapedText.slice(1, -1);

} else {
  // If postText was not found, create the safe_text field as an empty string
  // to prevent errors in the next node.
  item.json.safe_text = "";
}

// Return the entire item with the new 'safe_text' field added.
return item;

